// Decide if we should save this to Qdrant
const input = $('Prepare Training Data').first().json;
const userMessage = input.user_message || '';
const aiResponse = $input.first().json.output || '';

// Keywords that indicate this should be saved as knowledge
const saveKeywords = [
  'ejemplo', 'así deberías', 'responde así', 'cuando pregunten',
  'siempre', 'nunca', 'importante', 'recuerda', 'nuestro',
  'nuestros', 'vendemos', 'ofrecemos', 'horario', 'precio',
  'correcto', 'incorrecto', 'mejor', 'información'
];

const lowerMessage = userMessage.toLowerCase();
const shouldSave = saveKeywords.some(kw => lowerMessage.includes(kw)) || userMessage.length > 100;

// Prepare text to save (if applicable)
let textToSave = '';
if (shouldSave) {
  textToSave = `EJEMPLO DE ENTRENAMIENTO\n\nCliente pregunta: ${userMessage}\n\nRespuesta esperada: ${aiResponse}\n\nFecha de entrenamiento: ${input.timestamp}`;
}

return {
  json: {
    response: aiResponse,
    saved: shouldSave,
    text_to_save: textToSave,
    company_slug: input.company_slug,
    collection_name: input.collection_name,
    openai_api_key: input.openai_api_key,
    qdrant_host: input.qdrant_host
  }
};

// Prepare point for Qdrant
const prevData = $('Process Response').first().json;
const embedding = $input.first().json.data[0].embedding;

// Generate UUID
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

return {
  json: {
    id: uuid,
    vector: embedding,
    payload: {
      text: prevData.text_to_save,
      filename: 'training_examples.txt',
      category: 'entrenamiento',
      company_slug: prevData.company_slug,
      chunk_index: 0,
      total_chunks: 1
    },
    collection_name: prevData.collection_name,
    qdrant_host: prevData.qdrant_host,
    response: prevData.response
  }
};

// Return response (saved path)
const prevData = $('Prepare Qdrant Point').first().json;
return {
  json: {
    response: prevData.response,
    saved: true,
    message: 'Guardado en la base de conocimiento'
  }
};

// Return response (not saved path)
const prevData = $('Process Response').first().json;
return {
  json: {
    response: prevData.response,
    saved: false
  }
};
